/**
 * Build-time script: reads the standardized per-platform `results/<id>/results.json`
 * reports plus the algorithm catalogue, validates them against the JSON Schemas
 * in `schema/`, and produces `public/data/benchmarks.json` for the web app.
 *
 * No algorithm metadata is hardcoded here — categories come from the Rust
 * registry via `src/data/algorithms.json` (generated by `hash-bench metadata`).
 */
import { mkdir, readdir, readFile, stat, writeFile } from "node:fs/promises";
import { join, resolve } from "node:path";
import Ajv2020 from "ajv/dist/2020";

const ROOT = resolve(import.meta.dirname, "../..");
const RESULTS_DIR = join(ROOT, "results");
const SCHEMA_DIR = join(ROOT, "schema");
const ALGORITHMS_FILE = resolve(import.meta.dirname, "../src/data/algorithms.json");
const OUTPUT_DIR = resolve(import.meta.dirname, "../public/data");
const OUTPUT_FILE = join(OUTPUT_DIR, "benchmarks.json");

// ── Shapes emitted by the Rust binary (see schema/*.schema.json) ─────────────

interface ResultRow {
	algorithm: string;
	variant: string;
	size_bytes: number;
	threads: number;
	mean_ns: number;
	median_ns: number;
	stddev_ns: number;
	ci_lower_ns: number;
	ci_upper_ns: number;
	throughput_bps: number;
	samples: number;
}

interface ResultsReport {
	schema_version: number;
	generated_at_unix_ms: number;
	platform: {
		id: string;
		cpu_model: string | null;
		physical_cores: number;
		logical_cores: number;
		os: string;
		arch: string;
	};
	config: {
		sizes_bytes: number[];
		concurrency_levels: number[];
		warmup_ms: number;
		sample_count: number;
	};
	results: ResultRow[];
}

interface AlgorithmMeta {
	name: string;
	variant: string;
	crate: string;
	output_bits: number;
	output_kind: string;
	category: string;
	internally_parallel: boolean;
	keyed: boolean;
	dos_resistant: boolean;
	hardware_required: boolean;
	hardware_features: string[];
	notes: string;
}

interface AlgorithmsReport {
	schema_version: number;
	algorithms: AlgorithmMeta[];
}

// ── Shapes consumed by the web app ───────────────────────────────────────────

interface BenchmarkResult {
	platform: string;
	threads: number;
	algorithm: string;
	variant: string;
	size: string;
	size_bytes: number;
	mean_ns: number;
	median_ns: number;
	stddev_ns: number;
	ci_lower_ns: number;
	ci_upper_ns: number;
	throughput_bps: number;
}

interface PlatformInfo {
	id: string;
	display_name: string;
	cpu_model: string | null;
	physical_cores: number;
	logical_cores: number;
	os: string;
	arch: string;
	thread_counts: number[];
	sizes: string[];
}

interface ReportData {
	generated_at_unix_ms: number;
	platforms: PlatformInfo[];
	benchmarks: BenchmarkResult[];
	/** Keyed by `<algorithm>|<variant>` (matches the join key emitted below). */
	algorithms: Record<string, AlgorithmMeta>;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

async function exists(path: string): Promise<boolean> {
	try {
		await stat(path);
		return true;
	} catch {
		return false;
	}
}

/** Human-readable binary size label, e.g. 1024 → "1 KiB". */
function formatSize(bytes: number): string {
	const units = ["B", "KiB", "MiB", "GiB", "TiB"];
	let value = bytes;
	let unit = 0;
	while (value >= 1024 && unit < units.length - 1) {
		value /= 1024;
		unit++;
	}
	const rendered = Number.isInteger(value) ? value.toString() : value.toFixed(1);
	return `${rendered} ${units[unit]}`;
}

/** Compile a validator from a schema file. */
async function compileSchema(ajv: Ajv2020, file: string) {
	const schema = JSON.parse(await readFile(join(SCHEMA_DIR, file), "utf-8"));
	return ajv.compile(schema);
}

// ── Load + validate the algorithm catalogue ──────────────────────────────────

async function loadAlgorithmMeta(
	ajv: Ajv2020,
): Promise<Record<string, AlgorithmMeta>> {
	const validate = await compileSchema(ajv, "algorithms.v3.schema.json");

	if (!(await exists(ALGORITHMS_FILE))) {
		throw new Error(
			`Missing ${ALGORITHMS_FILE}. Run \`just gen-metadata\` to regenerate it.`,
		);
	}

	const report: AlgorithmsReport = JSON.parse(
		await readFile(ALGORITHMS_FILE, "utf-8"),
	);
	if (!validate(report)) {
		throw new Error(
			`algorithms.json failed schema validation: ${ajv.errorsText(validate.errors)}`,
		);
	}

	const algorithms: Record<string, AlgorithmMeta> = {};
	for (const alg of report.algorithms) {
		algorithms[`${alg.name}|${alg.variant}`] = alg;
	}
	return algorithms;
}

// ── Load + validate per-platform benchmark reports ───────────────────────────

async function loadReports(ajv: Ajv2020): Promise<ResultsReport[]> {
	const validate = await compileSchema(ajv, "results.v2.schema.json");
	const reports: ResultsReport[] = [];

	if (!(await exists(RESULTS_DIR))) {
		console.log("No results/ directory found. Generating empty data.");
		return reports;
	}

	const entries = await readdir(RESULTS_DIR, { withFileTypes: true });
	for (const entry of entries) {
		if (!entry.isDirectory()) continue;
		const file = join(RESULTS_DIR, entry.name, "results.json");
		if (!(await exists(file))) continue;

		const report: ResultsReport = JSON.parse(await readFile(file, "utf-8"));
		if (!validate(report)) {
			throw new Error(
				`${file} failed schema validation: ${ajv.errorsText(validate.errors)}`,
			);
		}
		reports.push(report);
	}

	return reports;
}

// ── Merge into the web app's report shape ────────────────────────────────────

function buildReportData(
	reports: ResultsReport[],
	algorithms: Record<string, AlgorithmMeta>,
): ReportData {
	const benchmarks: BenchmarkResult[] = [];
	const platforms: PlatformInfo[] = [];

	for (const report of reports) {
		const p = report.platform;
		const threadCounts = new Set<number>();
		const sizeLabels = new Map<string, number>();

		for (const row of report.results) {
			const size = formatSize(row.size_bytes);
			threadCounts.add(row.threads);
			sizeLabels.set(size, row.size_bytes);
			benchmarks.push({
				platform: p.id,
				threads: row.threads,
				algorithm: row.algorithm,
				variant: row.variant,
				size,
				size_bytes: row.size_bytes,
				mean_ns: row.mean_ns,
				median_ns: row.median_ns,
				stddev_ns: row.stddev_ns,
				ci_lower_ns: row.ci_lower_ns,
				ci_upper_ns: row.ci_upper_ns,
				throughput_bps: row.throughput_bps,
			});
		}

		platforms.push({
			id: p.id,
			display_name: p.cpu_model ?? p.id,
			cpu_model: p.cpu_model,
			physical_cores: p.physical_cores,
			logical_cores: p.logical_cores,
			os: p.os,
			arch: p.arch,
			thread_counts: [...threadCounts].sort((a, b) => a - b),
			sizes: [...sizeLabels.entries()]
				.sort(([, a], [, b]) => a - b)
				.map(([label]) => label),
		});
	}

	platforms.sort((a, b) => a.id.localeCompare(b.id));
	benchmarks.sort(
		(a, b) =>
			a.platform.localeCompare(b.platform) ||
			a.threads - b.threads ||
			a.algorithm.localeCompare(b.algorithm) ||
			a.variant.localeCompare(b.variant) ||
			a.size_bytes - b.size_bytes,
	);

	return {
		generated_at_unix_ms: Date.now(),
		platforms,
		benchmarks,
		algorithms,
	};
}

// ── Main ──────────────────────────────────────────────────────────────────────

const ajv = new Ajv2020({ allErrors: true });
const algorithmMeta = await loadAlgorithmMeta(ajv);
const reports = await loadReports(ajv);

const reportData = buildReportData(reports, algorithmMeta);
console.log(
	`Loaded ${reportData.benchmarks.length} benchmark results from ${reportData.platforms.length} platform(s).`,
);
if (reportData.platforms.length > 0) {
	console.log(
		`Platforms: ${reportData.platforms.map((p) => p.display_name).join(", ")}`,
	);
}

await mkdir(OUTPUT_DIR, { recursive: true });
await writeFile(OUTPUT_FILE, JSON.stringify(reportData));
console.log(`Written to ${OUTPUT_FILE}`);
